package com.zestok.mobile;  import com.getcapacitor.JSArray; import com.getcapacitor.JSObject; import com.getcapacitor.Plugin; import com.getcapacitor.PluginCall; import com.getcapacitor.PluginMethod; import com.getcapacitor.annotation.CapacitorPlugin;  import java.io.IOException; import java.net.DatagramPacket; import java.net.DatagramSocket; import java.net.HttpURLConnection; import java.net.Inet4Address; import java.net.InetAddress; import java.net.NetworkInterface; import java.net.SocketTimeoutException; import java.net.URL; import java.util.ArrayList; import java.util.Collections; import java.util.Enumeration; import java.util.List; import java.util.concurrent.ExecutorService; import java.util.concurrent.Executors; import java.util.concurrent.TimeUnit;  @CapacitorPlugin(name = "Discovery") public class DiscoveryPlugin extends Plugin {      private static final int DISCOVERY_PORT = 45678;     private static final int UDP_TIMEOUT_MS = 3000;     private static final String DISCOVER_REQ = "ZESTOK_DISCOVER_REQ";     private static final int HTTP_TIMEOUT_MS = 400;     private static final int HTTP_SCAN_THREADS = 30;      @PluginMethod     public void discoverServers(PluginCall call) {         try {             List<JSObject> servers = discover();             if (servers.isEmpty()) {                 servers = discoverHttp();             }             JSArray result = new JSArray();             for (JSObject s : servers) {                 result.put(s);             }             JSObject ret = new JSObject();             ret.put("servers", result);             call.resolve(ret);         } catch (Exception e) {             call.reject("Discovery failed: " + e.getMessage());         }     }      @PluginMethod     public void getLocalIp(PluginCall call) {         try {             String ip = getLocalIpAddress();             JSObject ret = new JSObject();             ret.put("ip", ip != null ? ip : "");             call.resolve(ret);         } catch (Exception e) {             call.reject("Failed to get local IP: " + e.getMessage());         }     }      private List<JSObject> discover() throws IOException {         List<JSObject> results = new ArrayList<>();         DatagramSocket socket = new DatagramSocket();         socket.setBroadcast(true);         socket.setSoTimeout(UDP_TIMEOUT_MS);          try {             byte[] sendData = DISCOVER_REQ.getBytes();              List<InetAddress> broadcastAddrs = getBroadcastAddresses();             for (InetAddress bcast : broadcastAddrs) {                 DatagramPacket sendPacket = new DatagramPacket(sendData, sendData.length, bcast, DISCOVERY_PORT);                 socket.send(sendPacket);             }              long deadline = System.currentTimeMillis() + UDP_TIMEOUT_MS;             while (System.currentTimeMillis() < deadline) {                 try {                     byte[] buf = new byte[256];                     DatagramPacket packet = new DatagramPacket(buf, buf.length);                     socket.receive(packet);                     String response = new String(packet.getData(), 0, packet.getLength()).trim();                     if (response.startsWith("ZESTOK_DISCOVER_RESP:")) {                         String[] parts = response.substring("ZESTOK_DISCOVER_RESP:".length()).split(":");                         if (parts.length >= 2) {                             JSObject obj = new JSObject();                             obj.put("ip", parts[0]);                             obj.put("port", parts[1]);                             if (!containsIp(results, parts[0])) {                                 results.add(obj);                             }                         }                     }                 } catch (SocketTimeoutException ignored) {                     break;                 }             }         } finally {             socket.close();         }         return results;     }      private List<JSObject> discoverHttp() {         String localIp = getLocalIpAddress();         if (localIp == null) return new ArrayList<>();          String subnet = localIp.substring(0, localIp.lastIndexOf('.'));         List<String> foundIps = Collections.synchronizedList(new ArrayList<>());         ExecutorService executor = Executors.newFixedThreadPool(HTTP_SCAN_THREADS);          for (int i = 1; i <= 254; i++) {             final String targetIp = subnet + "." + i;             executor.submit(() -> {                 try {                     URL url = new URL("http://" + targetIp + ":3000/api/health");                     HttpURLConnection conn = (HttpURLConnection) url.openConnection();                     conn.setConnectTimeout(HTTP_TIMEOUT_MS);                     conn.setReadTimeout(HTTP_TIMEOUT_MS);                     conn.setRequestMethod("GET");                     conn.setInstanceFollowRedirects(false);                     int code = conn.getResponseCode();                     if (code == 200 && !foundIps.contains(targetIp)) {                         foundIps.add(targetIp);                     }                     conn.disconnect();                 } catch (Exception ignored) {}             });         }          executor.shutdown();         try {             executor.awaitTermination(30, TimeUnit.SECONDS);         } catch (InterruptedException ignored) {}          List<JSObject> results = new ArrayList<>();         for (String ip : foundIps) {             JSObject obj = new JSObject();             obj.put("ip", ip);             obj.put("port", "3000");             results.add(obj);         }         return results;     }      private String getLocalIpAddress() {         try {             Enumeration<NetworkInterface> interfaces = NetworkInterface.getNetworkInterfaces();             while (interfaces.hasMoreElements()) {                 NetworkInterface ni = interfaces.nextElement();                 if (ni.isLoopback() || !ni.isUp()) continue;                 Enumeration<InetAddress> iaddrs = ni.getInetAddresses();                 while (iaddrs.hasMoreElements()) {                     InetAddress ia = iaddrs.nextElement();                     if (ia instanceof Inet4Address && !ia.isLoopbackAddress()) {                         return ia.getHostAddress();                     }                 }             }         } catch (Exception ignored) {}         return null;     }      private boolean containsIp(List<JSObject> list, String ip) {         for (JSObject obj : list) {             if (ip.equals(obj.getString("ip"))) {                 return true;             }         }         return false;     }      private List<InetAddress> getBroadcastAddresses() {         List<InetAddress> addrs = new ArrayList<>();         try {             Enumeration<NetworkInterface> interfaces = NetworkInterface.getNetworkInterfaces();             while (interfaces.hasMoreElements()) {                 NetworkInterface ni = interfaces.nextElement();                 if (ni.isLoopback() || !ni.isUp()) continue;                 Enumeration<InetAddress> iaddrs = ni.getInetAddresses();                 while (iaddrs.hasMoreElements()) {                     InetAddress ia = iaddrs.nextElement();                     if (ia instanceof java.net.Inet4Address) {                         byte[] addr = ia.getAddress();                         addr[3] = (byte) 255;                         addrs.add(InetAddress.getByAddress(addr));                     }                 }             }         } catch (Exception ignored) {}         return addrs;     } }